import{_ as t,o as a,c as o,ag as i}from"./chunks/framework.DTiDeF2Q.js";const x=JSON.parse('{"title":"นามแฝง Tmux | Dotfiles (TH)","titleTemplate":":title","description":"คำสั่ง tmux แบบสั้น ภาพรวมสำหรับ Dotfiles v0.2.495 รองรับ macOS, Linux และ WSL ผ่าน Dotfiles","frontmatter":{"title":"นามแฝง Tmux | Dotfiles","description":"คำสั่ง tmux แบบสั้น ภาพรวมสำหรับ Dotfiles v0.2.495 รองรับ macOS, Linux และ WSL ผ่าน Dotfiles","lang":"th-TH","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"นามแฝง Tmux | Dotfiles preview","canonical":"/th/aliases/tmux/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"นามแฝง Tmux","pageType":"docs","schemaType":"WebPage","permalink":"/th/aliases/tmux/"},"headers":[],"relativePath":"th/aliases/tmux/index.md","filePath":"th/aliases/tmux/index.md","lastUpdated":1773010926000}'),l={name:"th/aliases/tmux/index.md"};function s(d,e,c,m,n,u){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="นามแฝง-tmux" tabindex="-1">นามแฝง Tmux <a class="header-anchor" href="#นามแฝง-tmux" aria-label="Permalink to &quot;นามแฝง Tmux&quot;">​</a></h1><p>คำสั่ง tmux แบบสั้น</p><p>หน้านี้แนะนำกลุ่มนามแฝงหนึ่งกลุ่มและทางลัดคำสั่งทั่วไป อ่านหน้านี้ก่อนเพื่อทำความเข้าใจแบบแผนการตั้งชื่อ อินพุตที่คาดหวัง และรูปแบบการดำเนินการที่ปลอดภัย จากนั้นเปิดภาคผนวกอ้างอิงเพื่อดูรายการคำสั่งทั้งหมดและไวยากรณ์ที่แน่นอน นามแฝงเหล่านี้ลดการพิมพ์ซ้ำและรักษาพฤติกรรมเวิร์กโฟลว์ที่สม่ำเสมอบน macOS, Linux และ WSL</p><h2 id="เมื่อใดควรใช้" tabindex="-1">เมื่อใดควรใช้ <a class="header-anchor" href="#เมื่อใดควรใช้" aria-label="Permalink to &quot;เมื่อใดควรใช้&quot;">​</a></h2><p>ใช้หน้านี้ก่อนการทำงานเชลล์ประจำวันเมื่อคุณต้องการรูปแบบคำสั่งที่คาดเดาได้</p><h2 id="สิ่งที่รวมอยู่" tabindex="-1">สิ่งที่รวมอยู่ <a class="header-anchor" href="#สิ่งที่รวมอยู่" aria-label="Permalink to &quot;สิ่งที่รวมอยู่&quot;">​</a></h2><ul><li>นามแฝง: 11</li><li>ฟังก์ชันตัวช่วย: 1</li><li>ไฟล์ต้นฉบับ: 1</li></ul><h2 id="ตัวอย่างสั้น" tabindex="-1">ตัวอย่างสั้น <a class="header-anchor" href="#ตัวอย่างสั้น" aria-label="Permalink to &quot;ตัวอย่างสั้น&quot;">​</a></h2><ul><li><code>tma</code> → <code>&#39;tmux attach-session&#39; # แนบกับเซสชันล่าสุด</code></li><li><code>tmat</code> → <code>&#39;tmux attach-session -t&#39; # แนบกับเซสชันเฉพาะ</code></li><li><code>tmi</code> → <code>&#39;tmux info&#39; # แสดงข้อมูล tmux</code></li><li><code>tmka</code> → <code>&#39;tmux kill-server&#39; # ปิดทุกเซสชัน (เซิร์ฟเวอร์)</code></li><li><code>tmks</code> → <code>&#39;tmux kill-session -a&#39; # ปิดทุกเซสชันยกเว้นปัจจุบัน</code></li><li><code>tml</code> → <code>&#39;tmux list-sessions&#39; # แสดงรายการเซสชันทั้งหมด</code></li><li><code>tmlp</code> → <code>&#39;tmux list-panes&#39; # แสดงรายการ panes</code></li><li><code>tmls</code> → <code>&#39;tmux list-windows&#39; # แสดงรายการ windows</code></li><li><code>tmn</code> → <code>&#39;tmux new-session&#39; # เซสชันใหม่ไม่มีชื่อ</code></li><li><code>tmr</code> → <code>&#39;tmux source ~/.dotfiles/lib/configurations/tmux/tmux&#39; # โหลดค่าใหม่</code></li><li><code>tms</code> → <code>&#39;tmux new-session -s&#39; # เซสชันใหม่มีชื่อ</code></li></ul><h2 id="ขั้นตอนถัดไป" tabindex="-1">ขั้นตอนถัดไป <a class="header-anchor" href="#ขั้นตอนถัดไป" aria-label="Permalink to &quot;ขั้นตอนถัดไป&quot;">​</a></h2><p>เปิดรายการทั้งหมด:</p>',11)])])}const h=t(l,[["render",s]]);export{x as __pageData,h as default};
